class DeviceController:
    """Manages device outputs and controls."""

    def __init__(self):
        # LED on GPIO2 (built-in on most ESP32 boards)
        self.led = Pin(2, Pin.OUT, value=0)

        # Relay on GPIO4 (adjust as needed)
        try:
            self.relay = Pin(4, Pin.OUT, value=0)
        except Exception:
            self.relay = None

        # PWM output on GPIO5
        try:
            from machine import PWM
            self.pwm = PWM(Pin(5), freq=1000, duty=0)
        except Exception:
            self.pwm = None

        self.led_state = 0
        self.relay_state = 0
        self.pwm_duty = 0

    def set_led(self, state):
        """Turn LED on/off. state: 0=off, 1=on, 2=toggle."""
        if state == 2:
            self.led_state = 1 - self.led_state
        else:
            self.led_state = 1 if state else 0
        self.led.value(self.led_state)
        print("[CTRL] LED:", "ON" if self.led_state else "OFF")
        return self.led_state

    def set_relay(self, state):
        """Control relay. state: 0=off, 1=on, 2=toggle."""
        if state == 2:
            self.relay_state = 1 - self.relay_state
        else:
            self.relay_state = 1 if state else 0
        if self.relay:
            self.relay.value(self.relay_state)
        print("[CTRL] Relay:", "ON" if self.relay_state else "OFF")
        return self.relay_state

    def set_pwm(self, duty):
        """Set PWM duty cycle (0-100)."""
        self.pwm_duty = max(0, min(100, duty))
        if self.pwm:
            self.pwm.duty(int(self.pwm_duty / 100 * 1023))
        print("[CTRL] PWM duty:", self.pwm_duty, "%")
        return self.pwm_duty

    def process_command(self, cmd_bytes):
        """
        Process a general command from the mobile app.
        Command format: [CMD_ID(1byte), ...PARAMS]
        
        Commands:
          0x01 - Ping (returns "PONG")
          0x02 - Get all states
          0x03 - Reset device
          0x04 - Set LED brightness pattern [pattern_id]
          0x05 - Emergency stop (all outputs off)
          0x10 - Custom command
        """
        if not cmd_bytes or len(cmd_bytes) == 0:
            return b"ERR:EMPTY"

        cmd_id = cmd_bytes[0]
        params = cmd_bytes[1:] if len(cmd_bytes) > 1 else b""

        if cmd_id == 0x01:
            # Ping
            return b"PONG"

        elif cmd_id == 0x02:
            # Get all states: [led, relay, pwm_duty]
            return struct.pack("BBB", self.led_state, self.relay_state, self.pwm_duty)

        elif cmd_id == 0x03:
            # Reset/restart
            print("[CMD] Device reset requested")
            return b"OK:RESET"

        elif cmd_id == 0x04:
            # LED pattern
            pattern = params[0] if params else 0
            print("[CMD] LED pattern:", pattern)
            return b"OK:PATTERN"

        elif cmd_id == 0x05:
            # Emergency stop
            self.set_led(0)
            self.set_relay(0)
            self.set_pwm(0)
            print("[CMD] Emergency stop!")
            return b"OK:ESTOP"

        elif cmd_id == 0x10:
            # Custom command - extend as needed
            print("[CMD] Custom:", params)
            return b"OK:CUSTOM"

        else:
            return b"ERR:UNKNOWN"


class BLEDeviceServer:
    """Main BLE GATT Server for the IoT device."""

    def __init__(self, device_name="ESP32-IoT-Device"):
        self.device_name = device_name
        self.ble = bluetooth.BLE()
        self.ble.active(True)
        self.ble.irq(self._irq_handler)

        self.sensor_mgr = SensorManager()
        self.device_ctrl = DeviceController()

        self.connected_clients = set()
        self.notify_interval_ms = 5000  # Default 5 seconds
        self._last_notify_time = 0

        # Configuration
        self.manufacturer = "IoT Corp"
        self.model = "ESP32-CTL-v1"
        self.firmware_version = "1.0.0"

        # Register all GATT services
        self._register_services()

        # Set initial characteristic values
        self._init_values()

        # Start advertising
        self._start_advertising()

        print("=" * 50)
        print("BLE Device Server Started")
        print("Device Name:", self.device_name)
        print("=" * 50)
        self._print_service_info()

    def _register_services(self):
        """Register all GATT services and characteristics."""
        (
            # Device Info handles
            (self.h_manufacturer, self.h_model, self.h_firmware),
            # Sensor Service handles
            (self.h_temperature, self.h_humidity, self.h_light, self.h_battery),
            # Control Service handles
            (self.h_led, self.h_relay, self.h_pwm, self.h_command),
            # Config Service handles
            (self.h_dev_name, self.h_notify_interval, self.h_status),
        ) = self.ble.gatts_register_services(
            [_DEVICE_INFO_SERVICE, _SENSOR_SERVICE, _CONTROL_SERVICE, _CONFIG_SERVICE]
        )

        # Allow larger writes for command characteristic
        self.ble.gatts_set_buffer(self.h_command, 256)
        self.ble.gatts_set_buffer(self.h_dev_name, 64)

    def _init_values(self):
        """Set initial values for all characteristics."""
        # Device Info
        self.ble.gatts_write(self.h_manufacturer, self.manufacturer.encode())
        self.ble.gatts_write(self.h_model, self.model.encode())
        self.ble.gatts_write(self.h_firmware, self.firmware_version.encode())

        # Sensor initial values
        self._update_sensor_values()

        # Control initial states
        self.ble.gatts_write(self.h_led, struct.pack("B", 0))
        self.ble.gatts_write(self.h_relay, struct.pack("B", 0))
        self.ble.gatts_write(self.h_pwm, struct.pack("B", 0))
        self.ble.gatts_write(self.h_command, b"READY")

        # Config initial values
        self.ble.gatts_write(self.h_dev_name, self.device_name.encode())
        self.ble.gatts_write(
            self.h_notify_interval,
            struct.pack("<H", self.notify_interval_ms),
        )
        self.ble.gatts_write(self.h_status, self._get_status_payload())

    def _get_status_payload(self):
        """Build a status byte array for the status characteristic."""
        # Status format: [connected_count, led, relay, pwm, uptime_seconds(4bytes)]
        uptime = time.ticks_ms() // 1000
        return struct.pack(
            "<BBBBL",
            len(self.connected_clients),
            self.device_ctrl.led_state,
            self.device_ctrl.relay_state,
            self.device_ctrl.pwm_duty,
            uptime,
        )

    def _irq_handler(self, event, data):
        """Handle BLE events."""
        if event == _IRQ_CENTRAL_CONNECT:
            conn_handle, addr_type, addr = data
            self.connected_clients.add(conn_handle)
            print("[BLE] Client connected. Handle:", conn_handle)
            print("[BLE] Total connections:", len(self.connected_clients))
            # Update status
            self.ble.gatts_write(self.h_status, self._get_status_payload())
            # Continue advertising to allow multiple connections
            self._start_advertising()

        elif event == _IRQ_CENTRAL_DISCONNECT:
            conn_handle, addr_type, addr = data
            self.connected_clients.discard(conn_handle)
            print("[BLE] Client disconnected. Handle:", conn_handle)
            print("[BLE] Total connections:", len(self.connected_clients))
            # Update status
            self.ble.gatts_write(self.h_status, self._get_status_payload())
            # Resume advertising
            self._start_advertising()

        elif event == _IRQ_GATTS_WRITE:
            conn_handle, attr_handle = data
            value = self.ble.gatts_read(attr_handle)
            self._handle_write(conn_handle, attr_handle, value)

        elif event == _IRQ_GATTS_READ_REQUEST:
            conn_handle, attr_handle = data
            self._handle_read_request(conn_handle, attr_handle)

    def _handle_write(self, conn_handle, attr_handle, value):
        """Handle characteristic write from a client."""
        print("[WRITE] Handle:", attr_handle, "Value:", value)

        if attr_handle == self.h_led:
            # LED control: single byte 0=off, 1=on, 2=toggle
            if value and len(value) >= 1:
                state = self.device_ctrl.set_led(value[0])
                self.ble.gatts_write(self.h_led, struct.pack("B", state))
                self._notify_all(self.h_led, struct.pack("B", state))

        elif attr_handle == self.h_relay:
            # Relay control: single byte 0=off, 1=on, 2=toggle
            if value and len(value) >= 1:
                state = self.device_ctrl.set_relay(value[0])
                self.ble.gatts_write(self.h_relay, struct.pack("B", state))
                self._notify_all(self.h_relay, struct.pack("B", state))

        elif attr_handle == self.h_pwm:
            # PWM duty: single byte 0-100
            if value and len(value) >= 1:
                duty = self.device_ctrl.set_pwm(value[0])
                self.ble.gatts_write(self.h_pwm, struct.pack("B", duty))
                self._notify_all(self.h_pwm, struct.pack("B", duty))

        elif attr_handle == self.h_command:
            # General command processing
            response = self.device_ctrl.process_command(value)
            self.ble.gatts_write(self.h_command, response)
            # Notify the response back
            self._notify_all(self.h_command, response)

            # Handle reset command
            if response == b"OK:RESET":
                time.sleep_ms(500)
                import machine
                machine.reset()

        elif attr_handle == self.h_dev_name:
            # Update device name
            if value:
                self.device_name = value.decode("utf-8").strip()
                self.ble.gatts_write(self.h_dev_name, self.device_name.encode())
                print("[CONFIG] Device name changed to:", self.device_name)
                # Restart advertising with new name
                self._stop_advertising()
                self._start_advertising()

        elif attr_handle == self.h_notify_interval:
            # Update notification interval (little-endian uint16, in ms)
            if value and len(value) >= 2:
                self.notify_interval_ms = struct.unpack("<H", value[:2])[0]
                # Clamp to reasonable range
                self.notify_interval_ms = max(500, min(60000, self.notify_interval_ms))
                self.ble.gatts_write(
                    self.h_notify_interval,
                    struct.pack("<H", self.notify_interval_ms),
                )
                print("[CONFIG] Notify interval:", self.notify_interval_ms, "ms")

        # Update status after any control change
        self.ble.gatts_write(self.h_status, self._get_status_payload())

    def _handle_read_request(self, conn_handle, attr_handle):
        """Handle read request - update sensor values on demand."""
        if attr_handle == self.h_temperature:
            temp = self.sensor_mgr.read_temperature()
            self.ble.gatts_write(self.h_temperature, struct.pack("<f", temp))

        elif attr_handle == self.h_humidity:
            hum = self.sensor_mgr.read_humidity()
            self.ble.gatts_write(self.h_humidity, struct.pack("<f", hum))

        elif attr_handle == self.h_light:
            light = self.sensor_mgr.read_light_level()
            self.ble.gatts_write(self.h_light, struct.pack("<H", light))

        elif attr_handle == self.h_battery:
            bat = self.sensor_mgr.read_battery_level()
            self.ble.gatts_write(self.h_battery, struct.pack("B", bat))

        elif attr_handle == self.h_status:
            self.ble.gatts_write(self.h_status, self._get_status_payload())

    def _update_sensor_values(self):
        """Read all sensors and update characteristic values."""
        temp = self.sensor_mgr.read_temperature()
        hum = self.sensor_mgr.read_humidity()
        light = self.sensor_mgr.read_light_level()
        bat = self.sensor_mgr.read_battery_level()

        self.ble.gatts_write(self.h_temperature, struct.pack("<f", temp))
        self.ble.gatts_write(self.h_humidity, struct.pack("<f", hum))
        self.ble.gatts_write(self.h_light, struct.pack("<H", light))
        self.ble.gatts_write(self.h_battery, struct.pack("B", bat))

        return temp, hum, light, bat

    def _notify_all(self, char_handle, data):
        """Send notification to all connected clients."""
        for conn_handle in list(self.connected_clients):
            try:
                self.ble.gatts_notify(conn_handle, char_handle, data)
            except OSError:
                # Client may have disconnected
                self.connected_clients.discard(conn_handle)

    def _start_advertising(self):
        """Start BLE advertising."""
        # Build advertising payload
        adv_data = _encode_advertising_data(
            (_ADV_TYPE_FLAGS, b"\x06"),  # General discoverable, BR/EDR not supported
            (_ADV_TYPE_NAME, self.device_name),
        )

        # Scan response with service UUIDs
        scan_resp = _encode_advertising_data(
            (_ADV_TYPE_APPEARANCE, struct.pack("<H", 0x0540)),  # Generic sensor
        )

        self.ble.gap_advertise(
            100_000,  # Advertising interval in microseconds (100ms)
            adv_data=adv_data,
            resp_data=scan_resp,
            connectable=True,
        )
        print("[BLE] Advertising started as:", self.device_name)

    def _stop_advertising(self):
        """Stop BLE advertising."""
        self.ble.gap_advertise(None)

    def send_sensor_notifications(self):
        """Send sensor data notifications if interval has elapsed."""
        now = time.ticks_ms()
        if time.ticks_diff(now, self._last_notify_time) < self.notify_interval_ms:
            return

        self._last_notify_time = now

        if not self.connected_clients:
            return

        temp, hum, light, bat = self._update_sensor_values()

        # Send notifications
        self._notify_all(self.h_temperature, struct.pack("<f", temp))
        self._notify_all(self.h_humidity, struct.pack("<f", hum))
        self._notify_all(self.h_light, struct.pack("<H", light))
        self._notify_all(self.h_battery, struct.pack("B", bat))

        # Also update and notify status
        status = self._get_status_payload()
        self.ble.gatts_write(self.h_status, status)
        self._notify_all(self.h_status, status)

    def run(self):
        """Main loop - call this to keep the server running."""
        print("[BLE] Server running. Waiting for connections...")
        heartbeat_led = self.device_ctrl.led
        heartbeat_counter = 0

        while True:
            try:
                # Send periodic sensor notifications
                self.send_sensor_notifications()

                # Heartbeat blink when no client connected
                if not self.connected_clients:
                    heartbeat_counter += 1
                    if heartbeat_counter % 20 == 0:
                        heartbeat_led.value(1)
                        time.sleep_ms(50)
                        heartbeat_led.value(0)

                time.sleep_ms(50)

            except KeyboardInterrupt:
                print("\n[BLE] Shutting down...")
                self._stop_advertising()
                self.ble.active(False)
                break

            except Exception as e:
                print("[ERROR]", e)
                time.sleep_ms(1000)

    def _print_service_info(self):
        """Print service and characteristic information for developers."""
        print("\nRegistered Services:")
        print("-" * 50)
        print("1. Device Info Service: 0000180a-...")
        print("   - Manufacturer Name (R): handle", self.h_manufacturer)
        print("   - Model Number (R): handle", self.h_model)
        print("   - Firmware Rev (R): handle", self.h_firmware)
        print()
        print("2. Sensor Service: 12345678-...-9abc")
        print("   - Temperature (R/N) float32 C: handle", self.h_temperature)
        print("   - Humidity (R/N) float32 %: handle", self.h_humidity)
        print("   - Light Level (R/N) uint16: handle", self.h_light)
        print("   - Battery (R/N) uint8 %: handle", self.h_battery)
        print()
        print("3. Control Service: 12345678-...-0000")
        print("   - LED (R/W) uint8 [0=off,1=on,2=toggle]: handle", self.h_led)
        print("   - Relay (R/W) uint8 [0=off,1=on,2=toggle]: handle", self.h_relay)
        print("   - PWM (R/W) uint8 [0-100]: handle", self.h_pwm)
        print("   - Command (R/W/N) bytes: handle", self.h_command)
        print()
        print("4. Config Service: 12345678-...-c000")
        print("   - Device Name (R/W) string: handle", self.h_dev_name)
        print("   - Notify Interval (R/W) uint16 ms: handle", self.h_notify_interval)
        print("   - Status (R/N) bytes: handle", self.h_status)
        print("-" * 50)
        print()


